   194		public analyze(skill: Skill): Finding[] {
   195			const findings: Finding[] = [];
   196			let pipelines = this._extractPipelines(skill.instructionBody, "SKILL.md");
   197	
   198			for (const skillFile of skill.files) {
   199				if (
   200					skillFile.fileType === "python" ||
   201					skillFile.fileType === "bash" ||
   202					skillFile.fileType === "markdown" ||
   203					skillFile.fileType === "other"
