   212			if (this.policy.pipeline.dedupeEquivalentPipelines) {
   213				pipelines = this._dedupePipelines(pipelines);
   214			}
   215	
   216			for (const pipeline of pipelines) {
   217				findings.push(...this._analyzePipeline(pipeline));
