   260		public _dedupePipelines(pipelines: PipelineChain[]): PipelineChain[] {
   261			const byKey = new Map<string, PipelineChain>();
   262	
   263			for (const chain of pipelines) {
   264				let normalized = chain.raw.trim().split(/\s+/).join(" ");
   265				if (normalized.startsWith("$ ")) {
   266					normalized = normalized.slice(2);
   267				} else if (normalized.startsWith("> ")) {
   268					normalized = normalized.slice(2);
   269				}
   270	
   271				const key = `${chain.sourceFile}\u0000${normalized}`;
   272				const previous = byKey.get(key);
   273				if (previous === undefined || chain.lineNumber < previous.lineNumber) {
   274					byKey.set(key, chain);
   275				}
   276			}
   277	
   278			return [...byKey.values()];
   279		}
