   285		public _extractPipelines(content: string, sourceFile: string): PipelineChain[] {
   286			const pipelines: PipelineChain[] = [];
   287	
   288			for (const pattern of PIPELINE_PATTERNS) {
   289				pattern.lastIndex = 0;
   290				for (const match of content.matchAll(pattern)) {
   291					const raw = match[1] ?? match[0];
   292					for (const [index, lineRaw] of raw.split("\n").entries()) {
   293						const line = lineRaw.trim();
   294						if (line.length === 0 || line.startsWith("#")) {
   295							continue;
   296						}
   297						if (!line.includes("|")) {
   298							continue;
   299						}
   300	
   301						const chain = this._parsePipeline(line, sourceFile, index + 1);
   302						if (chain !== null && chain.nodes.length >= 2) {
   303							pipelines.push(chain);
   304						}
   305					}
   306				}
   307			}
   308	
   309			return pipelines;
   310		}
