   316		public _parsePipeline(raw: string, sourceFile: string, lineNumber: number): PipelineChain | null {
   317			const parts = raw
   318				.split(/\s*\|\s*(?!\|)/)
   319				.map((part) => part.trim())
   320				.filter((part) => part.length > 0);
   321			if (parts.length < 2) {
   322				return null;
   323			}
   324	
   325			const chain: PipelineChain = {
   326				raw,
   327				nodes: [],
   328				sourceFile,
   329				lineNumber,
   330			};
   331	
   332			for (const part of parts) {
   333				const tokens = part.split(/\s+/).filter((token) => token.length > 0);
   334				if (tokens.length === 0 || tokens[0] === undefined) {
   335					continue;
   336				}
   337	
   338				const command = basename(tokens[0]).toLowerCase();
   339				const argumentsList = tokens.slice(1);
   340				const node: CommandNode = {
   341					raw: part,
   342					command,
   343					arguments: argumentsList,
   344					inputTaints: new Set(),
   345					outputTaints: new Set(),
   346					isSource: false,
   347					isSink: false,
   348				};
   349	
   350				const sourceTaints = SOURCE_PATTERNS.get(command);
   351				if (sourceTaints !== undefined) {
   352					node.isSource = true;
   353					node.outputTaints = new Set(sourceTaints);
   354					const argsString = argumentsList.join(" ");
   355					for (const pattern of this._sensitiveFilePatterns) {
   356						if (pattern.test(argsString)) {
   357							node.outputTaints.add(TaintType.SENSITIVE_DATA);
   358							break;
   359						}
   360					}
   361				}
   362	
   363				chain.nodes.push(node);
   364			}
   365	
   366			return chain;
   367		}
