   504		public _assessTaintSeverity(
   505			sourceTaints: Set<TaintType>,
   506			sinkTaints: Set<TaintType>,
   507			chain: PipelineChain,
   508		): [Severity | null, string] {
   509			if (
   510				sourceTaints.has(TaintType.SENSITIVE_DATA) &&
   511				sinkTaints.has(TaintType.NETWORK_SEND) &&
   512				sourceTaints.has(TaintType.OBFUSCATION)
   513			) {
   514				return [
   515					"CRITICAL",
   516					`Pipeline reads sensitive data, obfuscates it, and sends it over the network: \`${chain.raw}\`. This is a classic data exfiltration pattern.`,
   517				];
   518			}
   519	
   520			if (sourceTaints.has(TaintType.SENSITIVE_DATA) && sinkTaints.has(TaintType.NETWORK_SEND)) {
   521				return [
   522					"CRITICAL",
   523					`Pipeline reads sensitive data and sends it over the network: \`${chain.raw}\`. This is likely data exfiltration.`,
   524				];
   525			}
   526	
   527			if (sourceTaints.has(TaintType.NETWORK_DATA) && sinkTaints.has(TaintType.CODE_EXECUTION)) {
   528				return [
   529					"HIGH",
   530					`Pipeline downloads data from the network and executes it: \`${chain.raw}\`. This is a remote code execution pattern.`,
   531				];
   532			}
   533	
   534			if (sourceTaints.has(TaintType.OBFUSCATION) && sinkTaints.has(TaintType.CODE_EXECUTION)) {
   535				return [
   536					"HIGH",
   537					`Pipeline uses obfuscation before code execution: \`${chain.raw}\`. Obfuscated execution hides malicious intent.`,
   538				];
   539			}
   540	
   541			if (sourceTaints.has(TaintType.SENSITIVE_DATA) && sinkTaints.has(TaintType.CODE_EXECUTION)) {
   542				return [
   543					"MEDIUM",
   544					`Pipeline reads data and passes it to code execution: \`${chain.raw}\`. Review for potential command injection.`,
   545				];
   546			}
   547	
   548			if (sourceTaints.has(TaintType.OBFUSCATION) && sinkTaints.has(TaintType.NETWORK_SEND)) {
   549				return [
   550					"MEDIUM",
   551					`Pipeline obfuscates data before sending to network: \`${chain.raw}\`. May indicate covert data exfiltration.`,
   552				];
   553			}
   554	
   555			return [null, ""];
   556		}
