   843				const block = match[1] ?? "";
   844				const startIndex = match.index ?? 0;
   845				const lineNumber = countNewlines(skill.instructionBody.slice(0, startIndex)) + 1;
   846				blocks.push(["SKILL.md", block, lineNumber]);
   847			}
   848	
   849			for (const skillFile of skill.files) {
   850				const content = skillFile.readContent();
   851				if (content.length === 0) {
   852					continue;
   853				}
   854	
   855				if (skillFile.fileType === "bash") {
   856					blocks.push([skillFile.relativePath, content, 1]);
   857				} else if (skillFile.fileType === "markdown") {
   858					codeBlockRegex.lastIndex = 0;
   859					for (const match of content.matchAll(codeBlockRegex)) {
   860						const block = match[1] ?? "";
   861						const startIndex = match.index ?? 0;
   862						const lineNumber = countNewlines(content.slice(0, startIndex)) + 1;
   863						blocks.push([skillFile.relativePath, block, lineNumber]);
