   876			const lines = blockText.split("\n");
   877			const matchedLines: number[] = [];
   878			let patternIndex = 0;
   879	
   880			for (const [lineIndex, rawLine] of lines.entries()) {
   881				const line = rawLine.trim();
   882				if (line.length === 0 || line.startsWith("#")) {
   883					continue;
   884				}
   885				const pattern = patterns[patternIndex];
   886				if (pattern?.test(line)) {
   887					matchedLines.push(lineIndex);
   888					patternIndex += 1;
   889					if (patternIndex >= patterns.length) {
   890						return matchedLines;
   891					}
   892				}
   893			}
   894	
   895			return null;
