    40		meta: Record<string, unknown>;
    41	}
    42	
    43	export interface YaraRuleMatch {
    44		ruleName: string;
    45		namespace: string;
    46		filePath: string | null;
    47		meta: YaraRuleMetadata;
    48		strings: YaraStringMatch[];
    49	}
    50	
    51	export interface YaraScannerOptions {
    52		rulesDirectory?: string;
    53		maxScanFileSize?: number;
    54	}
    55	
    56	function getLineContext(contentBytes: Buffer, offset: number): { lineNumber: number; lineContent: string } {
    57		let lineNumber = 1;
    58		for (let index = 0; index < offset; index += 1) {
    59			if (contentBytes[index] === 10) {
    60				lineNumber += 1;
    61			}
    62		}
    63	
    64		let lineStart = 0;
    65		for (let index = offset - 1; index >= 0; index -= 1) {
    66			if (contentBytes[index] === 10) {
    67				lineStart = index + 1;
    68				break;
    69			}
    70		}
    71	
    72		let lineEnd = contentBytes.length;
    73		for (let index = offset; index < contentBytes.length; index += 1) {
    74			if (contentBytes[index] === 10) {
    75				lineEnd = index;
    76				break;
    77			}
    78		}
    79	
    80		return {
    81			lineNumber,
    82			lineContent: contentBytes.subarray(lineStart, lineEnd).toString("utf-8").trim(),
    83		};
    84	}
    85	
    86	function mapMatchMetadata(rule: YaraRawRuleMatch): YaraRuleMetadata {
    87		return {
    88			ruleName: rule.ruleIdentifier,
    89			namespace: rule.namespace,
    90			tags: rule.tags,
    91			meta: rule.meta,
    92		};
    93	}
    94	
    95	export class YaraScanner {
    96		public readonly rulesDirectory: string;
    97		public readonly maxScanFileSize: number;
    98		private rules: YaraCompiledScanner | null;
    99	
   100		constructor(options: YaraScannerOptions = {}) {
   101			this.rulesDirectory = options.rulesDirectory ?? SkillScannerConstants.YARA_RULES_DIR;
   102			this.maxScanFileSize = options.maxScanFileSize ?? 50 * 1024 * 1024;
   103			this.rules = null;
   104			this._loadRules();
   105		}
   106	
   107		public scanContent(content: string, filePath: string | null = null): YaraRuleMatch[] {
   108			if (this.rules === null) {
   109				return [];
   110			}
   111	
   112			const contentBytes = Buffer.from(content, "utf-8");
   113			try {
   114				const matches = this.rules.scan(contentBytes);
   115				return matches.map(
   116					(rule): YaraRuleMatch => ({
   117						ruleName: rule.ruleIdentifier,
   118						namespace: rule.namespace,
   119						filePath,
   120						meta: mapMatchMetadata(rule),
   121						strings: rule.matches.map((match): YaraStringMatch => {
   122							const lineContext = getLineContext(contentBytes, match.offset);
   123							const matchedDataBytes = contentBytes.subarray(match.offset, match.offset + match.length);
   124							return {
   125								identifier: match.identifier,
   126								offset: match.offset,
   127								matchedData: matchedDataBytes.toString("utf-8"),
   128								lineNumber: lineContext.lineNumber,
   129								lineContent: lineContext.lineContent,
   130							};
   131						}),
   132					}),
   133				);
   134			} catch {
   135				return [];
   136			}
   137		}
   138	
   139		public scanFile(filePath: string, displayPath: string | null = null): YaraRuleMatch[] {
   140			const contextPath = displayPath ?? filePath;
   141	
   142			let fileBytes: Buffer;
   143			try {
   144				fileBytes = readFileSync(filePath);
   145			} catch {
   146				return [];
   147			}
   148	
   149			try {
   150				const decoder = new TextDecoder("utf-8", { fatal: true });
   151				const content = decoder.decode(fileBytes);
   152				return this.scanContent(content, contextPath);
   153			} catch {
   154				return this._scanFileBinary(filePath, contextPath);
   155			}
   156		}
   157	
   158		public getLoadedRules(): string[] {
   159			if (!existsSync(this.rulesDirectory) || !statSync(this.rulesDirectory).isDirectory()) {
   160				return [];
   161			}
   162			return readdirSync(this.rulesDirectory)
   163				.filter((fileName) => fileName.endsWith(".yara"))
   164				.map((fileName) => fileName.replace(/\.yara$/u, ""));
   165		}
   166	
   167		public _loadRules(): void {
   168			const rulesDirectory = resolve(this.rulesDirectory);
   169			if (!existsSync(rulesDirectory) || !statSync(rulesDirectory).isDirectory()) {
   170				throw new Error(`YARA rules directory not found: ${rulesDirectory}`);
   171			}
   172	
   173			const yaraFiles = readdirSync(rulesDirectory)
   174				.filter((fileName) => fileName.endsWith(".yara"))
   175				.sort((left, right) => left.localeCompare(right));
   176			if (yaraFiles.length === 0) {
   177				throw new Error(`No .yara files found in ${rulesDirectory}`);
   178			}
   179	
   180			try {
   181				const scanner = create() as unknown as YaraCompiledScanner;
   182				for (const yaraFile of yaraFiles) {
   183					scanner.addRuleFile(join(rulesDirectory, yaraFile));
   184				}
   185				this.rules = scanner;
   186			} catch (error) {
   187				throw new Error(`Failed to compile YARA rules: ${String(error)}`);
   188			}
   189		}
   190	
   191		public _scanFileBinary(filePath: string, displayPath: string): YaraRuleMatch[] {
   192			if (this.rules === null) {
   193				return [];
   194			}
   195	
   196			let fileBytes: Buffer;
   197			try {
   198				const fileSize = statSync(filePath).size;
   199				if (fileSize > this.maxScanFileSize) {
   200					return [];
   201				}
   202				fileBytes = readFileSync(filePath);
   203			} catch {
   204				return [];
   205			}
   206	
   207			try {
   208				const matches = this.rules.scan(fileBytes);
   209				return matches.map(
   210					(rule): YaraRuleMatch => ({
   211						ruleName: rule.ruleIdentifier,
   212						namespace: rule.namespace,
   213						filePath: displayPath,
   214						meta: mapMatchMetadata(rule),
   215						strings: rule.matches.map(
   216							(match): YaraStringMatch => ({
   217								identifier: match.identifier,
   218								offset: match.offset,
   219								matchedData: match.data,
   220								lineNumber: 0,
   221								lineContent: `[binary file at byte offset ${match.offset}]`,
   222							}),
   223						),
   224					}),
   225				);
   226			} catch {
   227				return [];
   228			}
   229		}
   230	}
